import{_ as t,o,c as r,ag as a}from"./chunks/framework.DLWhSH9p.js";const h=JSON.parse('{"title":"Mobile Setup","description":"","frontmatter":{},"headers":[],"relativePath":"mobile/setup.md","filePath":"mobile/setup.md"}'),s={name:"mobile/setup.md"};function i(n,e,l,c,d,u){return o(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="mobile-setup" tabindex="-1">Mobile Setup <a class="header-anchor" href="#mobile-setup" aria-label="Permalink to &quot;Mobile Setup&quot;">​</a></h1><h2 id="install-the-apk" tabindex="-1">Install the APK <a class="header-anchor" href="#install-the-apk" aria-label="Permalink to &quot;Install the APK&quot;">​</a></h2><ol><li>Download the latest APK from the <a href="https://expo.dev/accounts/xander-rudolph/projects/craft" target="_blank" rel="noreferrer">EAS build page</a>.</li><li>Transfer to your phone and open it. Allow &quot;Unknown sources&quot; in Android settings the first time.</li><li>Open <strong>Craft</strong> and sign in with your Keycloak account.</li><li>Open <strong>Settings</strong> → <strong>Server URL</strong> and point it at your CRAFT server&#39;s host (e.g. <code>https://craft.example.com</code>).</li><li>Tap <strong>Test connection</strong> — you should see a green check.</li></ol><h2 id="server-url" tabindex="-1">Server URL <a class="header-anchor" href="#server-url" aria-label="Permalink to &quot;Server URL&quot;">​</a></h2><p>The Server URL field takes the <strong>host root</strong> of your CRAFT deployment, not a specific path. The app appends <code>/api</code> for backend calls and derives the Keycloak URL by appending <code>/auth</code>. So a single host entry covers both:</p><ul><li>API → <code>&lt;server-url&gt;/api</code></li><li>Auth → <code>&lt;server-url&gt;/auth/realms/craft</code></li></ul><p>Use the same hostname you&#39;d type into a desktop browser to reach the studio (e.g. <code>https://craft.example.com</code>). The setting persists between launches.</p><div class="warning custom-block"><p class="custom-block-title">HTTP on Android</p><p>Android blocks cleartext HTTP by default. The Craft APK is built with <code>usesCleartextTraffic: true</code> so HTTP-only servers work without certificate setup — but production deployments should use HTTPS.</p></div><h2 id="building-from-source" tabindex="-1">Building from source <a class="header-anchor" href="#building-from-source" aria-label="Permalink to &quot;Building from source&quot;">​</a></h2><p>Building the APK yourself, running the app in Expo Go, or making changes to the mobile codebase is covered in the <a href="https://github.com/Mossworks-Labs/craft/blob/main/README.md#mobile-app-android" target="_blank" rel="noreferrer">project README</a> — that&#39;s contributor territory rather than user-facing setup.</p>',10)])])}const m=t(s,[["render",i]]);export{h as __pageData,m as default};
